from itertools import product
class Solution:
    def magicalSum(self, m, k, nums):
        MOD = 10 ** 9 + 7
        n = len(nums)
        total = 0
        for seq in product(range(n), repeat=m):
            s = 0
            for idx in seq:
                s += 1 << idx
            if bin(s).count('1') == k:
                p = 1
                for idx in seq:
                    p = (p * nums[idx]) % MOD
                total = (total + p) % MOD
        return total % MOD

