var magicalSum = function(m, k, nums) {
    const MOD = 1000000007n;
    const n = nums.length;
    const fact = new Array(m + 1).fill(1n);
    for (let i = 1; i <= m; i++) fact[i] = fact[i - 1] * BigInt(i) % MOD;
    const power = (a, b) => { let r = 1n; a %= MOD; while (b > 0n) { if (b & 1n) r = r * a % MOD; a = a * a % MOD; b >>= 1n; } return r; };
    const invFact = new Array(m + 1).fill(1n);
    invFact[m] = power(fact[m], MOD - 2n);
    for (let i = m - 1; i >= 0; i--) invFact[i] = invFact[i + 1] * BigInt(i + 1) % MOD;
    const popcount = (x) => { let c = 0; while (x > 0) { c += x & 1; x >>= 1; } return c; };
    let dp = new Map();
    const key = (u, c, b) => u + ',' + c + ',' + b;
    dp.set(key(0, 0, 0), 1n);
    for (let i = 0; i < n; i++) {
        const v = BigInt(nums[i]) % MOD;
        const powv = new Array(m + 1).fill(1n);
        for (let c = 1; c <= m; c++) powv[c] = powv[c - 1] * v % MOD;
        const ndp = new Map();
        for (const [kk, val] of dp) {
            const parts = kk.split(',');
            const used = parseInt(parts[0]), carry = parseInt(parts[1]), bits = parseInt(parts[2]);
            for (let c = 0; c <= m - used; c++) {
                const totalLow = carry + c;
                const bit = totalLow & 1;
                const ncarry = totalLow >> 1;
                const nbits = bits + bit;
                if (nbits > k) continue;
                const add = val * powv[c] % MOD * invFact[c] % MOD;
                const nk = key(used + c, ncarry, nbits);
                ndp.set(nk, ((ndp.get(nk) || 0n) + add) % MOD);
            }
        }
        dp = ndp;
    }
    let ans = 0n;
    for (const [kk, val] of dp) {
        const parts = kk.split(',');
        const used = parseInt(parts[0]), carry = parseInt(parts[1]), bits = parseInt(parts[2]);
        if (used !== m) continue;
        if (bits + popcount(carry) === k) ans = (ans + val) % MOD;
    }
    ans = ans * fact[m] % MOD;
    return Number(ans);
};
